        }
        .dpad-wrap {
          width: 156px;
          height: 156px;
        }
        .dpad {
          width: 136px;
          height: 136px;
        }
        .dpad-h {
          height: 46px;
        }
        .dpad-v {
          width: 46px;
        }
        .dpad-btn {
          font-size: 17px;
        }
        .dpad-up,
        .dpad-down {
          width: 46px;
          height: 46px;
        }
        .dpad-left,
        .dpad-right {
          width: 46px;
