        }
        .face-btn {
          width: 62px;
          height: 62px;
        }
        .ab-wrap {
          width: 156px;
          height: 156px;
        }
        .grooves {
          bottom: max(14px, env(safe-area-inset-bottom));
        }
        .groove {
          width: 28px;
        }
      }
      @media (max-width: 380px) {
        .dpad-wrap {
          width: 134px;
          height: 134px;
        }
        .dpad {
          width: 118px;
          height: 118px;
        }
        .dpad-h {
          height: 40px;
        }
        .dpad-v {
          width: 40px;
        }
        .dpad-up,
        .dpad-down {
          width: 40px;
          height: 40px;
        }
        .dpad-left,
        .dpad-right {
          width: 40px;
          height: 40px;
        }
        .dpad-btn {
          font-size: 15px;
        }
        .ab-wrap {
          width: 134px;
